+	if code != 0 {
+		t.Fatalf("exit code = %d; stderr=%q", code, errOut.String())
+	}
+	if got := <-gotQuery; got != "level=10&tell_slaves=1" {
+		t.Fatalf("query = %q; want level=10&tell_slaves=1", got)
