+func TestRunRawParsesFlagsAfterPath(t *testing.T) {
+	t.Parallel()
+
+	gotQuery := make(chan string, 1)
+	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
+		gotQuery <- r.URL.RawQuery
