+	}
+	if opts.ETag != "" {
+		q.Set("etag", opts.ETag)
+	}
+
+	data, err := c.getRead(ctx, "/Status", q)
+	if err != nil {
+		return Status{}, err
+	}
+
+	var status Status
+	if err := xml.NewDecoder(bytes.NewReader(data)).Decode(&status); err != nil {
+		return Status{}, err
+	}
+	return status, nil
+}
